2848 void ConstantDataSequential::destroyConstantImpl() {
2849   // Remove the constant from the StringMap.
2850   StringMap<std::unique_ptr<ConstantDataSequential>> &CDSConstants =
2851       getType()->getContext().pImpl->CDSConstants;
2852 
2853   auto Slot = CDSConstants.find(getRawDataValues());
2854 
2855   assert(Slot != CDSConstants.end() && "CDS not found in uniquing table");
2856 
2857   std::unique_ptr<ConstantDataSequential> *Entry = &Slot->getValue();
2858 
2859   // Remove the entry from the hash table.
2860   if (!(*Entry)->Next) {
2861     // If there is only one value in the bucket (common case) it must be this
2862     // entry, and removing the entry should remove the bucket completely.
2863     assert(Entry->get() == this && "Hash mismatch in ConstantDataSequential");
2864     getContext().pImpl->CDSConstants.erase(Slot);
2865     return;
2866   }
2867 
2868   // Otherwise, there are multiple entries linked off the bucket, unlink the
2869   // node we care about but keep the bucket around.
2870   while (true) {
2871     std::unique_ptr<ConstantDataSequential> &Node = *Entry;
2872     assert(Node && "Didn't find entry in its uniquing hash table!");
2873     // If we found our entry, unlink it from the list and we're done.
2874     if (Node.get() == this) {
2875       Node = std::move(Node->Next);
2876       return;
2877     }
2878 
2879     Entry = &Node->Next;
2880   }
2881 }
